#include<bits/stdc++.h>

#define int long long 

using namespace std;

inline int read()

{

    int s=0;

    char ch=getchar();

    while(ch<'0'||ch>'9') ch=getchar();

    while(ch>='0'&&ch<='9') s=s*10+ch-'0',ch=getchar();

    return s;

}

const int N=1010100,INF=2e9;

int n,q,b[N],tot,mx[N];

long long ans;

void gmi(int &x,int y){x=min(x,y);}

struct pr{int l,r,w;}e[N];

bool operator < (pr x,pr y){return x.w<y.w;}

int find(int x){return b[x]==x?b[x]:b[x]=find(b[x]);}

void mst()

{

    sort(e+1,e+tot+1);

    for(int i=0;i<n;i++) b[i]=i;

    for(int i=1;i<=tot;i++) {

	int l=e[i].l,r=e[i].r,w=e[i].w;

	int tx=find(l),ty=find(r);

	if(tx==ty) continue;

	b[tx]=ty;

	ans+=w;

    }

}

signed main()

{

    n=read();q=read();

    for(int i=0;i<n;i++) mx[i]=INF;

    for(int i=1;i<=q;i++) {

	int l=read(),r=read(),w=read();

	e[++tot]=(pr){l,r,w};

	gmi(mx[l],w+1);gmi(mx[r],w+2);

    }

    int d=INF,t=INF,be=0;

    for(int i=0;i<n;i++) if(mx[i]<t) be=i,t=mx[i];

    for(int i=1;i<=n;i++){

	d=min(d,mx[be]);

	e[++tot]=(pr){be,(be+1)%n,d};

	be=(be+1)%n;d+=2;

    }

    mst();

    cout<<ans<<'\n';

}
